import { useState, useRef, useEffect } from "react";
import "./Home.css";
import { FiUploadCloud, FiSearch, FiTrash2, FiRefreshCw, FiPlay } from "react-icons/fi";

function Home() {
    const [file, setFile] = useState(null);
    const [videoUrl, setVideoUrl] = useState(null);
    const [isScanning, setIsScanning] = useState(false);
    const [scanCompleted, setScanCompleted] = useState(false);
    const [detectedProducts, setDetectedProducts] = useState([]);
    const [activeBoxes, setActiveBoxes] = useState([]);
    const [checkoutStatus, setCheckoutStatus] = useState(null); // 'loading', 'success', null

    const videoRef = useRef(null);
    const scanTimeoutsRef = useRef([]);

    // Clean up timeouts on unmount
    useEffect(() => {
        return () => clearAllTimeouts();
    }, []);

    const clearAllTimeouts = () => {
        if (scanTimeoutsRef.current.length > 0) {
            scanTimeoutsRef.current.forEach(t => clearTimeout(t));
            scanTimeoutsRef.current = [];
        }
    };

    function handleUpload(event) {
        const selectedFile = event.target.files[0];
        if (selectedFile) {
            setFile(selectedFile);
            const url = URL.createObjectURL(selectedFile);
            setVideoUrl(url);
            setDetectedProducts([]);
            setActiveBoxes([]);
            setScanCompleted(false);
            setCheckoutStatus(null);
            clearAllTimeouts();
        }
    }

    function loadDemoVideo(event) {
        event.preventDefault();
        event.stopPropagation();
        // A high-quality public MP4 stock video containing supermarket items
        const demoUrl = "https://assets.mixkit.co/videos/preview/mixkit-shopping-bag-full-of-groceries-34279-large.mp4";
        setFile({ name: "demo_supermarket_items.mp4" });
        setVideoUrl(demoUrl);
        setDetectedProducts([]);
        setActiveBoxes([]);
        setScanCompleted(false);
        setCheckoutStatus(null);
        clearAllTimeouts();
    }

    function startDetection() {
        if (!videoUrl) return;

        setIsScanning(true);
        setScanCompleted(false);
        setDetectedProducts([]);
        setActiveBoxes([]);
        setCheckoutStatus(null);
        clearAllTimeouts();

        if (videoRef.current) {
            videoRef.current.currentTime = 0;
            videoRef.current.play().catch(err => {
                console.warn("Video autoplay prevented by browser. Click video to play.", err);
            });
        }

        // Timeline for detection simulation
        const timeline = [
            {
                time: 1500,
                product: { id: "bananas", name: "Organic Bananas (Bunch)", quantity: 3, price: 60 },
                box: { id: "bananas", label: "Bananas (98%)", top: "15%", left: "12%", width: "26%", height: "38%" }
            },
            {
                time: 3500,
                product: { id: "milk", name: "Fresh Milk 1L", quantity: 1, price: 50 },
                box: { id: "milk", label: "Milk (95%)", top: "20%", left: "55%", width: "24%", height: "55%" }
            },
            {
                time: 5500,
                product: { id: "bread", name: "Whole Wheat Bread", quantity: 2, price: 45 },
                box: { id: "bread", label: "Bread (93%)", top: "35%", left: "26%", width: "30%", height: "42%" }
            },
            {
                time: 7500,
                product: { id: "cookies", name: "Chocolate Cookies (Pack)", quantity: 1, price: 80 },
                box: { id: "cookies", label: "Cookies (97%)", top: "45%", left: "64%", width: "22%", height: "35%" }
            }
        ];

        const timeouts = [];

        timeline.forEach(item => {
            // Add product and bounding box overlay
            const t1 = setTimeout(() => {
                setDetectedProducts(prev => {
                    if (prev.some(p => p.id === item.product.id)) return prev;
                    return [...prev, item.product];
                });
                setActiveBoxes(prev => {
                    if (prev.some(b => b.id === item.box.id)) return prev;
                    return [...prev, item.box];
                });
            }, item.time);
            timeouts.push(t1);

            // Hide bounding box overlay after 2 seconds
            const t2 = setTimeout(() => {
                setActiveBoxes(prev => prev.filter(b => b.id !== item.box.id));
            }, item.time + 2000);
            timeouts.push(t2);
        });

        // Terminate scanning
        const tEnd = setTimeout(() => {
            setIsScanning(false);
            setScanCompleted(true);
        }, 9500);
        timeouts.push(tEnd);

        scanTimeoutsRef.current = timeouts;
    }

    function handleReset() {
        clearAllTimeouts();
        setIsScanning(false);
        setScanCompleted(false);
        setFile(null);
        setVideoUrl(null);
        setDetectedProducts([]);
        setActiveBoxes([]);
        setCheckoutStatus(null);
        if (videoRef.current) {
            videoRef.current.pause();
            videoRef.current.src = "";
        }
    }

    function updateQuantity(productId, delta) {
        setDetectedProducts(prev =>
            prev.map(p => {
                if (p.id === productId) {
                    const newQty = Math.max(1, p.quantity + delta);
                    return { ...p, quantity: newQty };
                }
                return p;
            })
        );
    }

    function deleteProduct(productId) {
        setDetectedProducts(prev => prev.filter(p => p.id !== productId));
    }

    function triggerCheckout() {
        if (detectedProducts.length === 0) return;
        setCheckoutStatus('loading');
        setTimeout(() => {
            setCheckoutStatus('success');
        }, 1500);
    }

    const totalItems = detectedProducts.reduce((sum, p) => sum + p.quantity, 0);
    const totalBill = detectedProducts.reduce((sum, p) => sum + (p.quantity * p.price), 0);

    return (
        <div className="home">
            <header className="header">
                <h1>🛒 SMART RETAIL CHECKOUT AI</h1>
            </header>

            <h2 className="title">
                Upload a shopping checkout video, detect products automatically, and checkout instantly.
            </h2>

            <div className="scanner-section">
                {!videoUrl ? (
                    <div className="upload-box-container" style={{ width: "100%", display: "flex", flexDirection: "column", alignItems: "center" }}>
                        <label htmlFor="upload" className="upload-box">
                            <FiUploadCloud className="upload-icon" />
                            <h2>Click to Upload Video</h2>
                            <p>Supports MP4, WebM formats</p>
                        </label>
                        <button type="button" className="demo-link-btn" onClick={loadDemoVideo}>
                            ✨ Don't have a video? Try our Demo Video
                        </button>
                    </div>
                ) : (
                    <div className="video-container">
                        <video
                            ref={videoRef}
                            className="preview-video"
                            src={videoUrl}
                            muted
                            playsInline
                            controls
                        />
                        {isScanning && <div className="scanner-line"></div>}
                        {isScanning && (
                            <div className="scanning-badge">
                                <span className="pulse-dot" style={{ width: 8, height: 8, borderRadius: "50%", background: "white", display: "inline-block" }}></span>
                                AI Scanning Active...
                            </div>
                        )}
                        {!isScanning && scanCompleted && (
                            <div className="ready-badge">
                                Analysis Complete
                            </div>
                        )}
                        {activeBoxes.map(box => (
                            <div
                                key={box.id}
                                className="bounding-box"
                                style={{
                                    top: box.top,
                                    left: box.left,
                                    width: box.width,
                                    height: box.height
                                }}
                            >
                                <span className="bounding-box-label">{box.label}</span>
                            </div>
                        ))}
                    </div>
                )}

                <input
                    type="file"
                    id="upload"
                    hidden
                    accept="video/*"
                    onChange={handleUpload}
                />

                {videoUrl && (
                    <div className="button-group">
                        <button
                            className="detect-btn"
                            onClick={startDetection}
                            disabled={isScanning}
                        >
                            <FiSearch /> {isScanning ? "Scanning..." : "Detect Products"}
                        </button>
                        <button className="reset-btn" onClick={handleReset}>
                            <FiRefreshCw /> Reset
                        </button>
                    </div>
                )}
            </div>

            {checkoutStatus === 'success' ? (
                <div style={{
                    background: "rgba(16, 185, 129, 0.15)",
                    border: "1px solid #10b981",
                    borderRadius: "12px",
                    padding: "20px",
                    textAlign: "center",
                    margin: "20px 0",
                    animation: "slideIn 0.3s ease"
                }}>
                    <h3 style={{ color: "#34d399", margin: "0 0 10px 0" }}>🎉 Payment Success!</h3>
                    <p style={{ color: "#a5b4fc", margin: 0 }}>
                        Thank you for using Smart Retail Checkout AI. Your bill of <strong>₹{totalBill.toFixed(2)}</strong> for {totalItems} items has been processed successfully.
                    </p>
                </div>
            ) : null}

            <div className="table-container">
                <h2>🛒 Shopping Cart</h2>
                <table>
                    <thead>
                        <tr>
                            <th>Product</th>
                            <th>Quantity</th>
                            <th>Price</th>
                            <th>Total</th>
                            <th>Action</th>
                        </tr>
                    </thead>
                    <tbody>
                        {detectedProducts.length === 0 ? (
                            <tr>
                                <td colSpan="5" className="empty-state">
                                    No products detected yet. Please upload a video and run detection.
                                </td>
                            </tr>
                        ) : (
                            detectedProducts.map(product => (
                                <tr key={product.id} className="product-row">
                                    <td style={{ fontWeight: "600" }}>{product.name}</td>
                                    <td>
                                        <div className="qty-control">
                                            <button
                                                className="qty-btn"
                                                onClick={() => updateQuantity(product.id, -1)}
                                                disabled={product.quantity <= 1 || isScanning}
                                            >
                                                -
                                            </button>
                                            <span className="qty-val">{product.quantity}</span>
                                            <button
                                                className="qty-btn"
                                                onClick={() => updateQuantity(product.id, 1)}
                                                disabled={isScanning}
                                            >
                                                +
                                            </button>
                                        </div>
                                    </td>
                                    <td>₹{product.price.toFixed(2)}</td>
                                    <td style={{ fontWeight: "700", color: "#818cf8" }}>₹{(product.price * product.quantity).toFixed(2)}</td>
                                    <td>
                                        <div className="action-cell">
                                            <button
                                                className="delete-btn"
                                                onClick={() => deleteProduct(product.id)}
                                                disabled={isScanning}
                                                title="Delete item"
                                            >
                                                <FiTrash2 />
                                            </button>
                                        </div>
                                    </td>
                                </tr>
                            ))
                        )}
                    </tbody>
                </table>
            </div>

            <div className="summary">
                <div className="card card-items">
                    <h3>Total Items</h3>
                    <h1>{totalItems}</h1>
                </div>

                <div className="card card-bill">
                    <h3>Total Bill</h3>
                    <h1>₹{totalBill.toFixed(2)}</h1>
                </div>
            </div>

            {detectedProducts.length > 0 && !isScanning && checkoutStatus !== 'success' && (
                <div style={{ display: "flex", justifyContent: "center", marginTop: "30px" }}>
                    <button
                        onClick={triggerCheckout}
                        disabled={checkoutStatus === 'loading'}
                        style={{
                            background: "linear-gradient(135deg, #10b981 0%, #059669 100%)",
                            color: "white",
                            border: "none",
                            padding: "16px 40px",
                            borderRadius: "12px",
                            fontSize: "1.1rem",
                            fontWeight: "700",
                            cursor: "pointer",
                            boxShadow: "0 10px 20px rgba(16, 185, 129, 0.2)",
                            display: "flex",
                            alignItems: "center",
                            gap: "10px",
                            transition: "all 0.2s ease"
                        }}
                    >
                        {checkoutStatus === 'loading' ? (
                            <>Processing Checkout...</>
                        ) : (
                            <>Proceed to Checkout (₹{totalBill.toFixed(2)})</>
                        )}
                    </button>
                </div>
            )}
        </div>
    );
}

export default Home;
